var query = ($json.query || '').trim();
var queryLower = query.toLowerCase();
var telefone = ($json.telefone || '').replace('@s.whatsapp.net', '');

var action = 'eliminar';

if (queryLower.indexOf('editar') > -1 || queryLower.indexOf('cambiar') > -1 || queryLower.indexOf('alterar') > -1 || queryLower.indexOf('mudar') > -1 || queryLower.indexOf('update') > -1 || queryLower.indexOf('modificar') > -1) {
  action = 'editar';
}

var stopWords = ['editar','cambiar','alterar','mudar','update','modificar','eliminar','borrar','quitar','excluir','apagar','delete','remove','remover','transaccion','transacao','gasto','ingreso','la','el','una','un','de','por','para','favor','puede','puedes','quero','quiero','valor','monto','precio'];

var words = queryLower.replace(/[?!.,;:$]/g, '').split(/\s+/);
var significant = [];
var nuevoMonto = 0;

for (var i = 0; i < words.length; i++) {
  var num = parseFloat(words[i]);
  if (!isNaN(num) && num > 0) {
    nuevoMonto = num;
  } else if (words[i].length > 1 && stopWords.indexOf(words[i]) === -1) {
    significant.push(words[i]);
  }
}

var searchTerm = '';
for (var j = 0; j < significant.length; j++) {
  var w = significant[j];
  searchTerm += w.charAt(0).toUpperCase() + w.slice(1);
  if (j < significant.length - 1) searchTerm += ' ';
}

return [{ json: { action: action, searchTerm: searchTerm, nuevoMonto: nuevoMonto, telefone: telefone } }];

var parsed = $node['Parsear Query'].json;
var resposta = $input.first().json;
var action = parsed.action;
var transacciones = resposta.transacciones || [];
var searchTerm = (parsed.searchTerm || '').toLowerCase();

function normalize(str) {
  return (str || '').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
}

var searchNorm = normalize(searchTerm);

if (!searchTerm) {
  return [{ json: { skip: true, mensagem: '⚠️ Necesito saber cuál transacción. Ejemplo: eliminar Pizza' } }];
}

var match = null;
for (var i = 0; i < transacciones.length; i++) {
  var descNorm = normalize(transacciones[i].descripcion);
  if (descNorm.indexOf(searchNorm) > -1) {
    match = transacciones[i];
    break;
  }
}

if (!match) {
  return [{ json: { skip: true, mensagem: '🔍 No encontré "' + parsed.searchTerm + '" en tus transacciones recientes.' } }];
}

if (action === 'eliminar') {
  return [{ json: { skip: false, action: 'eliminar', transaccion_id: match.id, nombre: match.descripcion, telefone: parsed.telefone } }];
}

if (action === 'editar') {
  if (!parsed.nuevoMonto || parsed.nuevoMonto <= 0) {
    return [{ json: { skip: true, mensagem: '⚠️ Encontré "' + match.descripcion + '" (actual: $' + match.monto + '). Necesito el nuevo valor. Ejemplo: editar Pizza 25000' } }];
  }
  return [{ json: { skip: false, action: 'editar', transaccion_id: match.id, monto: parsed.nuevoMonto, nombre: match.descripcion, telefone: parsed.telefone } }];
}

return [{ json: { skip: true, mensagem: '⚠️ Usa: eliminar [nombre], editar [nombre] [nuevo valor]' } }];

var resposta = $input.first().json;

if (resposta.mensagem) {
  return [{ json: { success: true, message: resposta.mensagem } }];
}

if (resposta.success) {
  return [{ json: { success: true, message: resposta.message || '✅ Operación completada.' } }];
}

return [{ json: { success: false, message: '❌ Error: ' + (resposta.error || 'Algo salió mal.') } }];
